def test_addition():
    return 2 + 2 == 4


def run_test(func, input_val, expected):
    actual = func(input_val)
    return {
        'passed': actual == expected,
        'actual': actual,
        'expected': expected
    }


def generate_test_cases(func, cases):
    results = []
    for input_val, expected in cases:
        results.append(run_test(func, input_val, expected))
    return results


def test_report(results):
    passed = sum(1 for r in results if r['passed'])
    total = len(results)
    return f'{passed}/{total} tests passed'
